import numpy as np

class InitializationStrategies:
    def __init__(self, n_params):
        self.n_params = n_params

    def random_full(self):
        return np.random.uniform(0, 2*np.pi, self.n_params)

    def identity_small(self, scale=0.01):
        return np.random.uniform(-scale, scale, self.n_params)

    def identity_gaussian(self, std=0.01):
        return np.random.normal(0, std, self.n_params)

    def zero_plus_noise(self, noise_scale=0.001):
        return np.zeros(self.n_params) + np.random.randn(self.n_params) * noise_scale

def compare_initializations(n_qubits, n_layers, n_samples=50):
    dim = 2 ** n_qubits
    n_params = n_qubits * n_layers
    init = InitializationStrategies(n_params)

    def circuit(params):
        state = np.zeros(dim, dtype=complex)
        state[0] = 1
        idx = 0
        for _ in range(n_layers):
            for q in range(n_qubits):
                theta = params[idx]
                c, s = np.cos(theta/2), np.sin(theta/2)
                new = np.zeros_like(state)
                for z in range(dim):
                    zf = z ^ (1 << (n_qubits-1-q))
                    new[z] = c*state[z] - s*state[zf]
                    new[zf] = s*state[z] + c*state[zf]
                state = new
                idx += 1
        return state

    def cost(params):
        state = circuit(params)
        return sum(np.abs(state[z])**2 * (1-2*(bin(z).count('1')%2)) for z in range(dim))

    results = {}
    strategies = [
        ('random_full', init.random_full),
        ('identity_0.01', lambda: init.identity_small(0.01)),
        ('identity_0.1', lambda: init.identity_small(0.1)),
        ('gaussian_0.01', lambda: init.identity_gaussian(0.01)),
    ]

    for name, init_fn in strategies:
        grads = []
        for _ in range(n_samples):
            params = init_fn()
            shift = np.pi/2
            pp, pm = params.copy(), params.copy()
            pp[0] += shift
            pm[0] -= shift
            grads.append((cost(pp) - cost(pm))/2)
        results[name] = np.var(grads)

    return results

results = compare_initializations(5, 5)
for name, var in results.items():
    print(f"{name}: Var[grad] = {var:.4e}")
